/*! jQuery fallback shim for SuperGrok Bridge chat pane.
 *  This is intentionally tiny and only supports the chat pane methods this app uses.
 *  Replace with official jQuery by running: python tools/fetch_jquery.py
 */
(function(window, document) {
  if (window.jQuery && window.$) return;
  function wrap(nodes) {
    var api = Object.create(wrap.fn);
    api.nodes = Array.prototype.slice.call(nodes || []);
    api.length = api.nodes.length;
    return api;
  }
  wrap.fn = {
    append: function(content) {
      this.nodes.forEach(function(node) {
        if (typeof content === 'string') node.insertAdjacentHTML('beforeend', content);
        else if (content && content.nodeType) node.appendChild(content.cloneNode(true));
      });
      return this;
    },
    text: function(value) {
      if (value === undefined) return this.nodes.map(function(node) { return node.textContent; }).join('');
      this.nodes.forEach(function(node) { node.textContent = value; });
      return this;
    },
    html: function(value) {
      if (value === undefined) return this.nodes[0] ? this.nodes[0].innerHTML : undefined;
      this.nodes.forEach(function(node) { node.innerHTML = value; });
      return this;
    },
    on: function(eventName, handler) {
      this.nodes.forEach(function(node) { node.addEventListener(eventName, handler); });
      return this;
    },
    ready: function(handler) {
      if (document.readyState !== 'loading') handler();
      else document.addEventListener('DOMContentLoaded', handler);
      return this;
    }
  };
  function jQuery(selector) {
    if (typeof selector === 'function') {
      return wrap([document]).ready(selector);
    }
    if (typeof selector === 'string') {
      return wrap(document.querySelectorAll(selector));
    }
    if (selector && selector.nodeType) {
      return wrap([selector]);
    }
    return wrap([]);
  }
  jQuery.fn = wrap.fn;
  jQuery.superGrokFallback = true;
  window.jQuery = window.$ = jQuery;
})(window, document);
